import numpy as np
from qiskit import QuantumCircuit
from qiskit.quantum_info import Statevector

qc = QuantumCircuit(3)
qc.h(0); qc.cx(0, 1); qc.cx(0, 2)
sv = Statevector(qc).data
inv = 1 / np.sqrt(2)
nz = {format(i, "03b"): sv[i] for i in range(8) if abs(sv[i]) > 1e-9}

def matches(states):
    if set(nz) != set(states):
        return False
    return all(np.isclose(nz[b], inv) for b in states)

claims = {
    "A": matches(["000", "111"]),
    "B": matches(["000", "100"]),
    "C": (len(nz) == 8) and all(np.isclose(abs(v), 1/np.sqrt(8)) for v in nz.values()),
    "D": matches(["000", "011"]),
}
nzr = {k: complex(round(v.real, 4), round(v.imag, 4)) for k, v in nz.items()}
evidence = {
    "A": f"nonzero basis states = {nzr}; claim {{000,111}} at 1/sqrt2 -> {claims['A']}",
    "B": f"nonzero = {nzr}; claim {{000,100}} -> {claims['B']}",
    "C": f"nonzero = {nzr} ({len(nz)} states); claim all-8-uniform -> {claims['C']}",
    "D": f"nonzero = {nzr}; claim {{000,011}} -> {claims['D']}",
}
proven = [k for k, v in claims.items() if v]
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"nonzero": {k: str(v) for k, v in nzr.items()}}})
